// Generates Lorem Ipsum.
#[component]
pub fn Lorem(
    #[prop(optional)]
    // Offset
    offset: u8,
    // Max 35 - offset
    sentences: u8,
) -> impl IntoView {
    let mut i = 0;
    let mut dot_iter = LOREM_IPSUM.match_indices(".").skip(offset as usize);
    let mut last_dot = 0;
    while i < sentences {
        if let Some((position, _)) = dot_iter.next() {
            last_dot = position;
        } else {
            break;
        }
        i += 1;
    }
    LOREM_IPSUM[0..last_dot].to_string()
}
